CREATE TABLE IF NOT EXISTS "tags" (
    "ID"   BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "NAME" VARCHAR(255) NOT NULL
);

CREATE TABLE IF NOT EXISTS "categories" (
    "ID"    BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "TITLE" VARCHAR(255) NOT NULL
);

CREATE TABLE IF NOT EXISTS "category_product" (
    "ID"           BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "category_id"  BIGINT NOT NULL,
    "product_key"  BIGINT NOT NULL,
    "NAME"         VARCHAR(255)  NOT NULL,
    "TYPE"         VARCHAR(100)  NOT NULL,
    "PRICE"        DECIMAL(19,2) NOT NULL,
    "MANUFACTURER" VARCHAR(255),
    "SKU"          VARCHAR(255),
    "TAG"          BIGINT,
    "VERSION"      BIGINT,
    CONSTRAINT fk_cp_category_id FOREIGN KEY ("category_id") REFERENCES "categories"("ID"),
    CONSTRAINT fk_cp_tag FOREIGN KEY ("TAG") REFERENCES "tags"("ID")
);

CREATE TABLE IF NOT EXISTS "customers" (
    "ID"    BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "NAME"  VARCHAR(255) NOT NULL,
    "EMAIL" VARCHAR(255) NOT NULL
);

CREATE TABLE IF NOT EXISTS "customer_order" (
    "ID"           BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "customer_id"  BIGINT NOT NULL,
    "order_key"    BIGINT NOT NULL,
    "DESCRIPTION"  VARCHAR(255) NOT NULL,
    CONSTRAINT fk_co_customer_id FOREIGN KEY ("customer_id") REFERENCES "customers"("ID")
);